1	//! Record-cell rendering (BEHAVIOR.md §3a, §3f): turning facts / rule instances
2	//! into the exact text that goes inside a record cell, including the observed
3	//! escaping, the fact-vs-function spacing, and the `\l`/`&nbsp;` line-wrapping
4	//! FORMAT.
5	//!
6	//! What is byte-exact here (verified against the corpus):
7	//!   * **Escaping** of record-label metacharacters `< > { } |`.
8	//!   * **Fact spacing** `Name( a, b )` (a space after `(` and before `)`) versus
9	//!     **function spacing** `f(a, b)` (no inner spaces) — mined over the corpus;
10	//!     a fact / relation symbol pads, an ordinary function application does not.
11	//!   * **Info-cell** shape `#<temporal> : <RuleName>` optionally followed by
12	//!     `[<action>, …]`.
13	//!   * The **wrap alignment**: a broken group's continuation lines are indented
14	//!     with `&nbsp;` runs to the column of the group's first element — i.e. just
15	//!     after `( ` for a fact, after `<` for a tuple, after `[` for an action list
16	//!     (verified across 188 192 wrapped cells: the indent always equals that
17	//!     first-element column). Physical segments are separated by `\l`.
18	//!
19	//! What is a documented GAP (pretty-printer internal, not derivable from output):
20	//! *when* the renderer chooses to break — the line-width budget and the group
21	//! nesting that drive it (BEHAVIOR.md §3a). The flat renderer below reproduces
22	//! every UN-wrapped cell exactly; [`fill`] reproduces the wrap FORMAT for a given
23	//! break decision but does not itself decide the breaks.
24	
25	use crate::term::Term;
26	
27	/// Escape the metacharacters that are special inside a graphviz record label:
28	/// `< > { } |` each get a leading backslash. Everything else (including single
29	/// quotes, `~ $ ^ * ⊕`, spaces) is literal. Observed in every record cell.
30	pub fn escape_record(s: &str) -> String {
31	    let mut out = String::with_capacity(s.len());
32	    for c in s.chars() {
33	        match c {
34	            '<' | '>' | '{' | '}' | '|' => {
35	                out.push('\\');
36	                out.push(c);
37	            }
38	            _ => out.push(c),
39	        }
40	    }
41	    out
42	}
43	
44	/// A fact / relation atom occupying one premise or conclusion cell, e.g.
45	/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
46	/// for a persistent fact); `args` are its term arguments.
47	#[derive(Clone, Debug)]
48	pub struct Fact {
49	    pub name: String,
50	    pub args: Vec<Term>,
51	}
52	
53	impl Fact {
54	    pub fn new(name: &str, args: Vec<Term>) -> Self {
55	        Fact { name: name.to_string(), args }
56	    }
57	
58	    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
59	    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
60	    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
61	    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
62	    pub fn render_flat(&self) -> String {
63	        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
64	        pad(&self.name, &inner)
65	    }
66	
67	    /// Flat rendering with abbreviations applied to registered sub-terms
68	    /// (`table` maps a term's full rendering to its abbreviation name).
69	    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
70	        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
71	        pad(&self.name, &inner)
72	    }
73	}
74	
75	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
76	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
77	fn pad(name: &str, args: &[String]) -> String {
78	    if args.is_empty() {
79	        format!("{}( )", name)
80	    } else {
81	        format!("{}( {} )", name, args.join(", "))
82	    }
83	}
84	
85	/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
86	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
87	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
88	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
89	    if actions.is_empty() {
90	        format!("#{} : {}", temporal, rule)
91	    } else {
92	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
93	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
94	    }
95	}
96	
97	/// Lay `items` out as a **fill** to a target `width`, starting at column
98	/// `open_col` (the alignment column of the group's first element). Returns the
99	/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
100	///
101	/// Greedy fill: keep appending `sep`-joined items to the current line while it
102	/// fits in `width`; otherwise start a new line. This reproduces the observed
103	/// packing (several short arguments share a line, then a break) **given** the
104	/// width; the width itself is the documented gap.
105	pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
106	    if items.is_empty() {
107	        return vec![String::new()];
108	    }
109	    let mut lines: Vec<String> = Vec::new();
110	    let mut cur = String::new();
111	    let mut col = open_col;
112	    for (i, it) in items.iter().enumerate() {
113	        let piece = if cur.is_empty() {
114	            it.clone()
115	        } else {
116	            format!("{}{}", sep, it)
117	        };
118	        if !cur.is_empty() && col + piece.chars().count() > width {
119	            lines.push(std::mem::take(&mut cur));
120	            col = open_col;
121	            cur.push_str(it);
122	            col += it.chars().count();
123	        } else {
124	            cur.push_str(&piece);
125	            col += piece.chars().count();
126	        }
127	        let _ = i;
128	    }
129	    lines.push(cur);
130	    lines
131	}
132	
133	/// Join physical `lines` (a FILL of same-aligned elements, e.g. a broken action
134	/// list `[a1, a2]`) into a single record-cell string using the observed wrap
135	/// format: each physical line is followed by `\l`, and every continuation line is
136	/// prefixed by `open_col` `&nbsp;` entities (the verified alignment indent). The
137	/// trailing `\l` after the last line is part of the observed format (graphviz
138	/// left-justification). The caller escapes the line contents first (via
139	/// [`escape_record`]) — `\l` and `&nbsp;` are literal control sequences and must
140	/// not be escaped.
141	///
142	/// This reproduces the fill case where the closing delimiter stays attached to
143	/// the last element (`… )]`). A function/fact whose closing `)` breaks onto its
144	/// *own* line at the functor column is a distinct layout the pretty-printer's
145	/// break decision produces (a documented GAP), not modelled here.
146	pub fn join_wrapped(lines: &[String], open_col: usize) -> String {
147	    let indent = "&nbsp;".repeat(open_col);
148	    let mut out = String::new();
149	    for (i, ln) in lines.iter().enumerate() {
150	        if i > 0 {
151	            out.push_str(&indent);
152	        }
153	        out.push_str(ln);
154	        out.push_str("\\l");
155	    }
156	    out
157	}
158	
