177	        let f = Fact::new("Out", vec![Term::app("pk", vec![Term::fresh("ltkA")])]);
178	        assert_eq!(f.render_flat(), "Out( pk(~ltkA) )");
179	        // !SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )
180	        let f = Fact::new(
181	            "!SessionKey",
182	            vec![
183	                Term::tuple(vec![Term::pubv("A"), Term::pubv("A"), Term::exp(Term::cst("g"), Term::fresh("ex"))]),
184	                Term::pubv("A"),
185	                Term::fresh("ex"),
186	            ],
187	        );
188	        assert_eq!(f.render_flat(), "!SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )");
189	    }
