47	impl RuleInstance {
48	    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
49	        RuleInstance {
50	            temporal: temporal.into(),
51	            rule: rule.into(),
52	            role: Role::UNDEFINED.into(),
53	            premises: Vec::new(),
54	            actions: Vec::new(),
55	            conclusions: Vec::new(),
56	            fillcolor: fillcolor.into(),
57	            fontcolor: "black".into(),
58	        }
59	    }
60	    pub fn premises(mut self, f: Vec<Fact>) -> Self {
61	        self.premises = f;
62	        self
63	    }
64	    pub fn actions(mut self, f: Vec<Fact>) -> Self {
65	        self.actions = f;
66	        self
67	    }
68	    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
69	        self.conclusions = f;
70	        self
71	    }
72	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
73	        self.role = r.into();
74	        self.fontcolor = fontcolor.into();
75	        self
76	    }
77	    fn cell_count(&self) -> usize {
78	        let p = self.premises.len();
79	        let c = self.conclusions.len();
80	        p + 1 /* info */ + c
81	    }
82	}
