167	/// A proof-state graph description: nodes in emission order, edges, and an
168	/// optional pre-rendered legend (inner HTML of the `plain` node) plus the invis
169	/// edges wiring it in.
170	#[derive(Clone, Debug, Default)]
171	pub struct System {
172	    pub nodes: Vec<GraphNode>,
173	    pub edges: Vec<SysEdge>,
174	    /// Legend inner HTML (from [`crate::abbrev::Abbreviator::legend_html`]); if
175	    /// non-empty a `{ rank="sink"; … }` block is appended.
176	    pub legend_html: Option<String>,
177	    /// Invis edges to the legend node (emitted after the sink block).
178	    pub legend_edges: Vec<(EndRef, ())>,
179	}
